var b64array = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";

function encode64(input) {
    var base64 = "";
    var hex = "";
    var chr1, chr2, chr3 = "";
    var enc1, enc2, enc3, enc4 = "";
    var i = 0;
    do {
        chr1 = input.charCodeAt(i++);
        chr2 = input.charCodeAt(i++);
        chr3 = input.charCodeAt(i++);
        enc1 = chr1 >> 2;
        enc2 = ((chr1 & 3) << 4) | (chr2 >> 4);
        enc3 = ((chr2 & 15) << 2) | (chr3 >> 6);
        enc4 = chr3 & 63;
        if (isNaN(chr2)) {
            enc3 = enc4 = 64;
        } else if (isNaN(chr3)) {
            enc4 = 64;
        }
        base64 = base64  +
            b64array.charAt(enc1) +
            b64array.charAt(enc2) +
            b64array.charAt(enc3) +
            b64array.charAt(enc4);
        chr1 = chr2 = chr3 = "";
        enc1 = enc2 = enc3 = enc4 = "";
    } while (i < input.length);
    return base64;
}

function clickLink(tosplit, actx, myrandoms) {
 var wl = String(window.name).length;

 var insidehtml = "inside.html?";
 if(actx) { insidehtml = "insidex.html?"; }
 if(tosplit == "") { alert("Warning! The connection was not established!\The client start is now interrupted!"); return false; }
 var doonexit = "close";
 if(document.getElementById("mainimg") == null || (myrandoms && myrandoms.location.href != null)) { doonexit = "close"; }
 else { doonexit = "referrer"; }
 var todocu = insidehtml;
 var find = tosplit.indexOf("|");
 if(find > -1) {
  todocu = tosplit.substring(0, find) + todocu;
  tosplit = tosplit.substring(find + 1);
 }
 var mycook = readCookie("tswebsecuredtest");
 if(!mycook) {
  createCookie("tswebsecuredtest", "yes", 365);
  mycook = readCookie("tswebsecuredtest");
 }

 var actrun = 1;
 if(mycook == "yes" || wl > 10) {
  var locationhref = document.location.href.split('/');
  var loclen = locationhref.length;
  todocu = "";
  for(var i = 0; i < loclen - 1; i++) {
   todocu += locationhref[i] + "/";
  }
  todocu += insidehtml;

  if(wl < 11) {
   while(readCookie("tswebsecuredrun" + actrun)) {
    actrun++;
   }
  }
  var enc64str = encode64(escape(doonexit + "|" + document.location.href + "|" + tosplit)).replace(/=/g, '_');
  if(wl > 10) {
    window.name = enc64str;
    try { window.opener.name = window.name; } catch(e) { }
  } else {
    createCookie("tswebsecuredrun" + actrun, enc64str, 1/24/60/2);
    window.name = enc64str;
    try { window.opener.name = window.name; } catch(e) { }
  }
 }

 if(!myrandoms || myrandoms.location.href == null) {
  if(!mycook && wl < 11) { document.location.replace(todocu+enc64str); }
  else { document.location.replace(todocu + actrun); }
 } else {
  if(!mycook && wl < 11) { myrandoms.location.replace(todocu+enc64str); }
  else { myrandoms.location.replace(todocu + actrun); }
 }
}

function addClass (element, className) {
 if(!hasClass(element, className)) {
	if (element.className) {
		element.className += " " + className;
	} else {
		element.className = className;
	}
  }
}

function removeClass(element, className) {
	var regexp = addClass[className];
	if (!regexp) {
		regexp = addClass[className] = new RegExp("(^|\\s)" + className + "(\\s|$)");
	}
	element.className = element.className.replace(regexp, "$2");
}

function hasClass(element, className) {
	var regexp = addClass[className];
	if (!regexp) {
		regexp = addClass[className] = new RegExp("(^|\\s)" + className + "(\\s|$)");
	}
	return regexp.test(element.className);
}

function toggleClass(element, className) {
	if (hasClass(element, className)) {
		removeClass(element, className);
	} else {
		addClass(element, className);
	}
}

